class Solution:
    def findWinningPlayer(self, skills, k):
        n = len(skills)
        champion = 0
        wins = 0
        for i in range(1, n):
            if skills[i] > skills[champion]:
                champion = i
                wins = 1
            else:
                wins += 1
            if wins >= k:
                return champion
        return champion

