var findWinningPlayer = function(skills, k) {
    const n = skills.length;
    let champion = 0, wins = 0;
    for (let i = 1; i < n; i++) {
        if (skills[i] > skills[champion]) {
            champion = i;
            wins = 1;
        } else {
            wins++;
        }
        if (wins >= k) return champion;
    }
    return champion;
};
